const transcription = $input.first().json.text;

if (!transcription || transcription.trim() === '') {
  throw new Error('Audio transcription failed or returned empty. Check your audio file format (.mp3, .mp4, .wav, .m4a)');
}

const webhookData = $('Receive Meeting Transcript').first().json;
const body = webhookData.body || {};

const meetingTitle = body.meeting_title || 'Untitled Meeting';
const meetingDate = body.meeting_date || new Date().toISOString().split('T')[0];

return [{
  json: {
    transcript: transcription.trim().replaceAll('\n', ' '),
    meeting_title: meetingTitle,
    meeting_date: meetingDate
  }
}];

