parameters.jsCode:
const body = $input.first().json.body;

if (!body || !body.transcript || body.transcript.trim() === '') {
  throw new Error('Missing required field: transcript. Please send your meeting transcript in the POST body as JSON.');
}

const meetingTitle = body.meeting_title || 'Untitled Meeting';
const meetingDate = body.meeting_date || new Date().toISOString().split('T')[0];
const transcript = body.transcript.trim().replaceAll('\n', ' ');

return [{
  json: {
    transcript,
    meeting_title: meetingTitle,
    meeting_date: meetingDate
  }
}];

const rawContent = $input.first().json.choices[0].message.content;

let parsed;
try {
  const clean = rawContent.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error('AI returned invalid JSON. Raw response: ' + rawContent);
}

// Get meeting meta — works for both text and audio paths
let meetingTitle = 'Untitled Meeting';
let meetingDate = new Date().toISOString().split('T')[0];

try {
  const textData = $('Validate & Prepare Input').first().json;
  meetingTitle = textData.meeting_title || meetingTitle;
  meetingDate = textData.meeting_date || meetingDate;
} catch (e) {
  try {
    const audioData = $('Prepare Audio Input').first().json;
    meetingTitle = audioData.meeting_title || meetingTitle;
    meetingDate = audioData.meeting_date || meetingDate;
  } catch (e2) {
    // use defaults set above
  }
}

const docTitle = `Meeting Summary — ${meetingTitle} — ${meetingDate}`;

// Format Action Items
let actionItemsText = '';
if (Array.isArray(parsed.action_items) && parsed.action_items.length > 0) {
  parsed.action_items.forEach((item, i) => {
    actionItemsText += `${i + 1}. ${item.task}\n   Owner: ${item.owner || 'TBD'}\n   Deadline: ${item.deadline || 'Not specified'}\n\n`;
  });
} else {
  actionItemsText = 'No action items identified.\n';
}

// Format Decisions
let decisionsText = '';
if (Array.isArray(parsed.decisions) && parsed.decisions.length > 0) {
  parsed.decisions.forEach(d => { decisionsText += `• ${d}\n`; });
} else {
  decisionsText = 'No explicit decisions recorded.\n';
}

// Format Next Agenda
let agendaText = '';
if (Array.isArray(parsed.next_agenda) && parsed.next_agenda.length > 0) {
  parsed.next_agenda.forEach((a, i) => { agendaText += `${i + 1}. ${a}\n`; });
} else {
  agendaText = 'No agenda suggestions.\n';
}

const docContent = `MEETING SUMMARY\n${'='.repeat(50)}\nMeeting: ${meetingTitle}\nDate: ${meetingDate}\nGenerated: ${new Date().toLocaleString()}\n\n${'─'.repeat(50)}\n\n📌 EXECUTIVE SUMMARY\n${'─'.repeat(50)}\n${parsed.summary || 'No summary generated.'}\n\n${'─'.repeat(50)}\n\n✅ DECISIONS MADE\n${'─'.repeat(50)}\n${decisionsText}\n${'─'.repeat(50)}\n\n📋 ACTION ITEMS\n${'─'.repeat(50)}\n${actionItemsText}${'─'.repeat(50)}\n\n🗓️ NEXT MEETING AGENDA\n${'─'.repeat(50)}\n${agendaText}\n${'─'.repeat(50)}\nAuto-generated by n8n | Meeting Summary Workflow`;

return [{
  json: {
    doc_title: docTitle,
    doc_content: docContent,
    meeting_title: meetingTitle,
    meeting_date: meetingDate,
    summary: parsed.summary,
    decisions: parsed.decisions,
    action_items: parsed.action_items,
    next_agenda: parsed.next_agenda,
    action_items_count: Array.isArray(parsed.action_items) ? parsed.action_items.length : 0
  }
}];

